'use client';

import React from 'react';

type StarBorderProps<T extends React.ElementType> = React.ComponentPropsWithoutRef<T> & {
  as?: T;
  className?: string;
  children?: React.ReactNode;
  color?: string;
  speed?: React.CSSProperties['animationDuration'];
  thickness?: number;
};

const StarBorder = <T extends React.ElementType = 'button'>({
  as,
  className = '',
  color = 'white',
  speed = '6s',
  thickness = 1,
  children,
  ...rest
}: StarBorderProps<T>) => {
  const Component = as || 'button';

  const borderRadius = 24;
  const innerRadius = borderRadius - thickness;

  return (
    <Component
      className={`relative inline-flex overflow-hidden ${className}`}
      {...(rest as any)}
      style={{
        padding: `${thickness}px`,
        borderRadius: `${borderRadius}px`,
        ...(rest as any).style
      }}
    >
      <div
        className="absolute w-[300%] h-[50%] opacity-70 bottom-[-11px] right-[-250%] rounded-full animate-star-movement-bottom z-0"
        style={{
          background: `radial-gradient(circle, ${color}, transparent 10%)`,
          animationDuration: speed
        }}
      />
      <div
        className="absolute w-[300%] h-[50%] opacity-70 top-[-10px] left-[-250%] rounded-full animate-star-movement-top z-0"
        style={{
          background: `radial-gradient(circle, ${color}, transparent 10%)`,
          animationDuration: speed
        }}
      />
      <div
        className="relative z-[1] bg-gradient-to-b from-black to-gray-900 border border-white/[0.06] text-white text-center text-sm font-medium inline-flex items-center justify-center"
        style={{
          borderRadius: `${innerRadius}px`,
          padding: '12px 28px',
        }}
      >
        {children}
      </div>
    </Component>
  );
};

export default StarBorder;
